public static TypeAdapter<?> getTypeAdapter(ConstructorConstructor constructorConstructor, Gson gson, TypeToken<?> fieldType, JsonAdapter annotation) {
    Class<?> value = annotation.value();
    TypeAdapter<?> typeAdapter;
    if (TypeAdapter.class.isAssignableFrom(value)) {
        Class<TypeAdapter<?>> typeAdapterClass = (Class<TypeAdapter<?>>) value;
        typeAdapter = constructorConstructor.get(TypeToken.get(typeAdapterClass)).construct();
    } else if (TypeAdapterFactory.class.isAssignableFrom(value)) {
        Class<TypeAdapterFactory> typeAdapterFactory = (Class<TypeAdapterFactory>) value;
        typeAdapter = constructorConstructor.get(TypeToken.get(typeAdapterFactory))
            .construct()
            .create(gson, fieldType);
    } else {
        throw new IllegalArgumentException(
            "@JsonAdapter value must be TypeAdapter or TypeAdapterFactory reference.");
    }
    if (typeAdapter == null) return null;
    if (fieldType.getRawType() == null) {
        throw new IllegalArgumentException("Interface cannot be instantiated");
    }
    return typeAdapter.nullSafe();
}

